//go:build vectors

package ingest

import (
	"context"
	"os"
	"path/filepath"
	"testing"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
)

func testPipeline(t *testing.T) (*Pipeline, string) {
	t.Helper()
	dir := t.TempDir()
	indexPath := filepath.Join(dir, "test.bleve")

	ix, err := NewIndexer(indexPath, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	t.Cleanup(func() { ix.Close() })

	emb := embedder.NewMockEmbedder(768)
	secCfg := config.SecurityConfig{
		ExtensionAllowlist: []string{".md", ".txt"},
		FilenameBlocklist:  []string{".env.md"},
		DirectoryBlocklist: []string{"node_modules", ".git"},
		MaxFileSizeBytes:   1 * 1024 * 1024,
	}

	p := NewPipeline(ix, emb, secCfg, 16000)
	return p, dir
}

func TestPipelineIndexSingleFile(t *testing.T) {
	p, dir := testPipeline(t)

	docPath := filepath.Join(dir, "test.md")
	content := `---
title: "Test Doc"
kind: reference
---

## Section One

Content of section one.

## Section Two

Content of section two.
`
	os.WriteFile(docPath, []byte(content), 0644)

	result, err := p.IndexPath(context.Background(), docPath, "project", "reference", false)
	if err != nil {
		t.Fatalf("IndexPath: %v", err)
	}

	if result.Indexed != 1 {
		t.Errorf("Indexed = %d, want 1", result.Indexed)
	}
	if result.Chunks != 2 {
		t.Errorf("Chunks = %d, want 2", result.Chunks)
	}
}

func TestPipelineIncrementalSkip(t *testing.T) {
	p, dir := testPipeline(t)

	docPath := filepath.Join(dir, "test.md")
	content := `## Section One

Content.
`
	os.WriteFile(docPath, []byte(content), 0644)

	// First index
	result1, err := p.IndexPath(context.Background(), docPath, "project", "reference", false)
	if err != nil {
		t.Fatalf("first index: %v", err)
	}
	if result1.Indexed != 1 {
		t.Errorf("first: Indexed = %d, want 1", result1.Indexed)
	}

	// Second index (unchanged)
	result2, err := p.IndexPath(context.Background(), docPath, "project", "reference", false)
	if err != nil {
		t.Fatalf("second index: %v", err)
	}
	if result2.Unchanged != 1 {
		t.Errorf("second: Unchanged = %d, want 1", result2.Unchanged)
	}
	if result2.Indexed != 0 {
		t.Errorf("second: Indexed = %d, want 0", result2.Indexed)
	}
}

func TestPipelineForceReindex(t *testing.T) {
	p, dir := testPipeline(t)

	docPath := filepath.Join(dir, "test.md")
	os.WriteFile(docPath, []byte("## Section\n\nContent."), 0644)

	// First index
	p.IndexPath(context.Background(), docPath, "project", "reference", false)

	// Force reindex
	result, err := p.IndexPath(context.Background(), docPath, "project", "reference", true)
	if err != nil {
		t.Fatalf("force index: %v", err)
	}
	if result.Indexed != 1 {
		t.Errorf("force: Indexed = %d, want 1", result.Indexed)
	}
}

func TestPipelineIndexDirectory(t *testing.T) {
	p, dir := testPipeline(t)

	docsDir := filepath.Join(dir, "docs")
	os.Mkdir(docsDir, 0755)

	os.WriteFile(filepath.Join(docsDir, "one.md"), []byte("## A\n\nContent A."), 0644)
	os.WriteFile(filepath.Join(docsDir, "two.md"), []byte("## B\n\nContent B."), 0644)
	os.WriteFile(filepath.Join(docsDir, "skip.go"), []byte("package main"), 0644) // Should be filtered

	result, err := p.IndexPath(context.Background(), docsDir, "project", "reference", false)
	if err != nil {
		t.Fatalf("IndexPath directory: %v", err)
	}

	if result.Indexed != 2 {
		t.Errorf("Indexed = %d, want 2 (only .md files)", result.Indexed)
	}
}

func TestPipelineRejectsBlockedFile(t *testing.T) {
	p, dir := testPipeline(t)

	blockedPath := filepath.Join(dir, ".env.md")
	os.WriteFile(blockedPath, []byte("## Secret\n\nPassword."), 0644)

	_, err := p.IndexPath(context.Background(), blockedPath, "project", "reference", false)
	if err == nil {
		t.Fatal("expected error for blocked file")
	}
}

func TestPipelineNonexistentPath(t *testing.T) {
	p, _ := testPipeline(t)

	_, err := p.IndexPath(context.Background(), "/nonexistent/path", "project", "reference", false)
	if err == nil {
		t.Fatal("expected error for nonexistent path")
	}
}
